INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Multi-type monitoring$q$, $q$Monitors HTTP/HTTPS, ping, port, keyword, cron job, DNS, SSL certificate, domain expiration, and UDP endpoints.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Multi-location checks$q$, $q$Verifies downtime from several global regions before alerting, cutting down on false positives.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Multi-channel alerting$q$, $q$Sends alerts via email, SMS, voice call, push notification, and integrations like Slack, Teams, Discord, and PagerDuty.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Public status pages$q$, $q$Branded, password-protectable status pages that display live and historical uptime to end users.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Incident management$q$, $q$Lets teams log notes, track incident timelines, and coordinate responses from within the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Maintenance windows$q$, $q$Suppresses alerts during scheduled downtime so planned maintenance doesn't trigger false alarms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Team access controls$q$, $q$Role-based login and notify seats let organizations control who can view, edit, or receive alerts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$SSL and domain monitoring$q$, $q$Tracks SSL certificate validity and domain expiration dates to prevent surprise outages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Generous free plan with 50 monitors, no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Very quick setup with a simple, no-frills interface$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Wide range of monitor types beyond basic HTTP checks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Affordable entry-level paid pricing compared to enterprise APM tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Large integration library for alerting and status pages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Free plan is limited to 5-minute check intervals, too slow for latency-sensitive services$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Deeper analytics and longer data retention require higher-tier paid plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Not a full observability or APM platform like Datadog or New Relic$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$SMS/voice alerts require separately purchased credits$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Some advanced features like custom SSO are enterprise-only$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Is UptimeRobot free to use?$q$, $q$Yes, UptimeRobot offers a permanent free plan supporting up to 50 monitors with 5-minute check intervals and no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$How often does UptimeRobot check my site on the free plan?$q$, $q$Free plan monitors are checked every 5 minutes; paid plans reduce this to 60 seconds, and Enterprise plans check every 30 seconds.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Who owns UptimeRobot?$q$, $q$UptimeRobot was founded in 2010 by Daniel Rimille and Umut Muhaddisoglu and has been owned by the investment firm Pale Fire Capital since 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Does UptimeRobot monitor SSL certificates?$q$, $q$Yes, it tracks SSL certificate validity and domain expiration and can alert before either lapses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Can I create a public status page with UptimeRobot?$q$, $q$Yes, paid and free plans both support customizable status pages, with more pages and branding options on higher tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$How is UptimeRobot different from Uptime Kuma?$q$, $q$UptimeRobot is a hosted commercial SaaS service, while Uptime Kuma is a free, open-source uptime monitor you install and host yourself.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$What alert channels does UptimeRobot support?$q$, $q$Email, SMS, voice calls, mobile push notifications, and integrations such as Slack, Microsoft Teams, Discord, and PagerDuty.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Does UptimeRobot offer a money-back guarantee?$q$, $q$Yes, new paid subscriptions come with a 14-day money-back guarantee.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Solo developers monitoring personal projects$q$, $q$Indie developers use the free plan to watch small sites, side projects, and APIs without paying anything.$q$, $q$Solo developers and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Agencies monitoring client websites$q$, $q$Digital agencies use Team and Enterprise plans with branded status pages to monitor and report on many client sites at once.$q$, $q$Web agencies and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$SaaS teams tracking API and infrastructure uptime$q$, $q$Engineering teams monitor production APIs, DNS records, and SSL certificates to catch outages before customers do.$q$, $q$SaaS and DevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Free$q$, $q$€0$q$, $q$monthly$q$, NULL, $q$["50 monitors","5-minute check interval","1 status page","3 months data retention","5 integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Solo$q$, $q$€10/month (€9/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 50 monitors","60-second checks","3 status pages","12 months data retention","API and multi-location monitoring"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Team$q$, $q$€38/month (€33/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["100 monitors","60-second checks","100 status pages","3 notify/login seats","24 months data retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$Enterprise$q$, $q$From €82/month (€69/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["200+ monitors","30-second checks","Unlimited status pages","SOC 2/GDPR/CCPA compliance","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$overview$q$, $q$What Is UptimeRobot$q$, 2, ARRAY[$q$UptimeRobot is a cloud-based monitoring service that continuously checks whether websites, APIs, servers, and other endpoints are online and performing correctly. Founded in 2010 and now owned by Pale Fire Capital, it has grown into one of the most widely used uptime monitoring tools, watching millions of monitors for individual developers, agencies, and larger engineering teams.$q$, $q$The service works by pinging a target URL, port, or keyword from multiple locations around the world on a set interval, then firing alerts the moment a check fails so a false positive from a single region does not trigger unnecessary noise. Beyond basic up/down checks, it also tracks SSL certificate and domain expiration dates, response times, and DNS record changes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$UptimeRobot supports HTTP/HTTPS, ping, port, keyword, cron job, DNS, SSL, and UDP monitoring, with multi-location checks to reduce false alarms. Alerting covers email, SMS, voice calls, mobile push notifications, and more than a dozen integrations such as Slack, Microsoft Teams, Discord, and PagerDuty.$q$, $q$Customers can build branded, password-protectable public status pages to communicate incidents to their own users, and collaborate on incidents internally with notes and timelines. Maintenance windows let teams silence alerts during planned downtime, and role-based access controls govern who on a team can view or edit monitors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40705dad-5bab-4f5b-a448-d25aaa9e4cbc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$UptimeRobot's Free plan includes 50 monitors checked every 5 minutes with 3 months of data retention, making it usable for personal projects and small sites without a credit card. Paid plans, Solo, Team, and Enterprise, drop the check interval to 60 seconds (30 seconds on Enterprise), add more monitors, longer retention, more status pages, and team seats, starting at roughly 10 euro per month and scaling up based on monitor count and features like SOC 2 and GDPR compliance on Enterprise.$q$, $q$SMS and voice alert credits are sold separately as one-time top-ups, and all paid subscriptions come with a 14-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Unified traces, metrics, and logs$q$, $q$Correlates distributed traces, application metrics, and logs in one dashboard instead of separate tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$OpenTelemetry-native$q$, $q$Built around the OpenTelemetry standard for instrumentation, avoiding proprietary agent lock-in.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$ClickHouse-backed storage$q$, $q$Uses the ClickHouse columnar database for fast queries over high-cardinality, high-volume telemetry data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Service graph and RED metrics$q$, $q$Visualizes service dependencies and highlights request rate, error rate, and duration bottlenecks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Multi-source ingestion$q$, $q$Accepts data from Prometheus, Vector, FluentBit, and CloudWatch in addition to OpenTelemetry.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$AI/MCP integration$q$, $q$Exposes an MCP server so AI assistants like Claude can query telemetry data in natural language.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Flexible deployment$q$, $q$Available as a managed cloud service or self-hosted via Docker, Kubernetes, or Ansible.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Open-source Community Edition$q$, $q$AGPL-3.0-licensed self-hosted edition with no feature limits, hosted on GitHub.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Fully open source and self-hostable with no artificial feature caps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Usage-based pricing with no per-seat charges, unlike many APM vendors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Built on open standards (OpenTelemetry, ClickHouse) that avoid lock-in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Significantly cheaper than Datadog or New Relic at scale per public comparisons$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Generous free tier for both cloud and self-hosted use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Smaller ecosystem and community than established players like Datadog or Grafana$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Self-hosting requires operating and scaling a ClickHouse cluster$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Less mature enterprise tooling (SSO, advanced RBAC) than large incumbent APM vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Documentation and integrations still maturing relative to bigger observability platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Is Uptrace open source?$q$, $q$Yes, the Uptrace Community Edition is open source under the AGPL-3.0 license and free to self-host with no feature limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$What database does Uptrace use?$q$, $q$Uptrace stores telemetry data in ClickHouse, a columnar database chosen for fast queries over high-cardinality data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Does Uptrace support OpenTelemetry?$q$, $q$Yes, Uptrace is built natively around the OpenTelemetry standard for collecting traces, metrics, and logs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$How much does Uptrace Cloud cost?$q$, $q$Uptrace Cloud includes 50GB of data and 5,000 timeseries free per month, then bills usage-based per gigabyte and per million metric datapoints.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Can I self-host Uptrace for free?$q$, $q$Yes, the Community Edition can be self-hosted for free via Docker, Kubernetes, or Ansible with no feature restrictions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Does Uptrace charge per user seat?$q$, $q$No, Uptrace includes unlimited users, services, and hosts on every plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$What is Uptrace an alternative to?$q$, $q$Uptrace is commonly compared to Datadog, New Relic, Splunk, and Grafana/Tempo/Loki stacks as a lower-cost, open-source observability option.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Where is Uptrace based?$q$, $q$Uptrace was founded in 2021 and is based in Chisinau, Moldova.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Replacing expensive APM vendors$q$, $q$Engineering teams migrate from Datadog or New Relic to cut observability costs while keeping trace, metric, and log visibility.$q$, $q$Platform and SRE teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Self-hosted observability for compliance$q$, $q$Organizations with data residency or budget constraints self-host Uptrace to keep telemetry data in their own infrastructure.$q$, $q$Regulated or cost-conscious enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$OpenTelemetry-native microservices monitoring$q$, $q$Teams already instrumented with OpenTelemetry use Uptrace to visualize service dependencies and debug latency across microservices.$q$, $q$Backend and DevOps engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Community Edition (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open source under AGPL-3.0","No feature limits","Deploy via Docker, Kubernetes, or Ansible"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Cloud Free Tier$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["50GB traces/logs/metrics per month","5,000 metric timeseries","No credit card required"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$Cloud Pay-as-you-go$q$, $q$From $0.075-$0.10/GB ingested$q$, $q$usage-based$q$, NULL, $q$["Volume discounts at scale","Unlimited users, services, and hosts","$0.025 per million metric datapoints"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$overview$q$, $q$What Is Uptrace$q$, 2, ARRAY[$q$Uptrace is an open-source observability and application performance monitoring platform that brings traces, metrics, and logs together in one dashboard, built specifically around the OpenTelemetry standard so teams avoid vendor lock-in to a proprietary agent.$q$, $q$Founded in 2021 and based in Chisinau, Moldova, Uptrace stores telemetry data in ClickHouse, a fast columnar database, which allows it to handle very high-cardinality attributes and large data volumes at a lower cost than many closed-source APM vendors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Uptrace provides distributed tracing, metrics, and log correlation in a single unified view, along with a service graph that visualizes dependencies between services and surfaces request rate, error rate, and latency (RED metrics). It ingests data natively from OpenTelemetry SDKs and collectors, plus Prometheus, Vector, FluentBit, and AWS CloudWatch.$q$, $q$An MCP server integration lets AI assistants such as Claude query and summarize telemetry data conversationally. Deployment is flexible, running as a managed cloud service or self-hosted via Docker, Kubernetes, or Ansible, with the self-hosted Community Edition released under the AGPL-3.0 open-source license.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Uptrace Cloud includes 50GB of traces, logs, and metrics plus 5,000 metric timeseries free every month. Beyond that, billing is usage-based: traces and logs are charged per gigabyte ingested (starting around $0.075-$0.10/GB with volume discounts as usage scales) and metrics are billed per million datapoints, with extended retention priced separately per gigabyte-month or timeseries-month.$q$, $q$There are no per-seat, per-host, or per-service fees, and organizations can self-host the Community Edition for free with no feature restrictions, or pay for a licensed on-premises deployment with dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e7a0b53e-f0d9-4f9d-ac95-70d431887088', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Multi-platform feed generation$q$, $q$Builds RSS feeds from Reddit, Hacker News, Lemmy, Mbin, PieFed, Lobsters, and GitHub.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Score and keyword filtering$q$, $q$Filters posts by minimum score, keywords, and timeframe to reduce noise in the resulting feed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Posts-per-day tuning$q$, $q$Lets users configure the target volume of posts delivered per day for a comfortable reading pace.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Embedded media$q$, $q$Includes videos, image galleries, and thumbnails directly inside the generated feed entries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Content parsing$q$, $q$Extracts clean article text and featured images from linked pages using built-in parsers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$AI article summaries$q$, $q$Optionally generates AI summaries of linked articles using OpenAI, Anthropic, Gemini, Mistral, DeepSeek, or Ollama.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Self-hosted deployment$q$, $q$Runs on the user's own infrastructure via Docker or PHP, keeping data and configuration fully under user control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Open-source codebase$q$, $q$Source is publicly available on GitHub for inspection, modification, and self-improvement by the community.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Completely free and open source with no subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Fine-grained filtering keeps feeds low-volume and high-signal$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Supports multiple social platforms beyond just Reddit$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Optional AI summaries save time reading linked articles$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Full control over data since it runs on your own server$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Requires self-hosting and basic technical setup, not a hosted SaaS$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$AI summaries require your own third-party API key and incur their own costs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$No official support team, relies on community and GitHub issues$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Limited to supported source platforms rather than arbitrary websites$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Is Upvote RSS free?$q$, $q$Yes, Upvote RSS is completely free and open source; you only pay for your own hosting and any optional AI API usage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$What platforms can Upvote RSS pull posts from?$q$, $q$It supports Reddit, Hacker News, Lemmy, Mbin, PieFed, Lobsters, and GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Do I need to self-host Upvote RSS?$q$, $q$Yes, it is a self-hosted tool typically deployed via Docker or a PHP-capable web server; there is no official hosted version.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Can Upvote RSS summarize articles with AI?$q$, $q$Yes, it can generate AI summaries of linked articles using providers such as OpenAI, Anthropic, Gemini, Mistral, DeepSeek, or Ollama, using your own API key.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Who created Upvote RSS?$q$, $q$Upvote RSS was created by developer John Warne and is maintained as an open-source project on GitHub.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$How do I filter which posts appear in my feed?$q$, $q$You can set a minimum score threshold, keyword filters, a timeframe, and a target number of posts per day when building a feed.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Does Upvote RSS work with any RSS reader?$q$, $q$Yes, since it outputs standard RSS feeds, it works with any feed reader that supports RSS or Atom subscriptions.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Is Upvote RSS the same as Upvoty?$q$, $q$No, they are unrelated products. Upvote RSS generates RSS feeds from social platforms, while Upvoty is a separate customer feedback and feature-voting SaaS tool.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Curating a low-noise Reddit feed$q$, $q$Users generate a filtered feed of only the highest-scoring posts from specific subreddits to avoid checking Reddit directly.$q$, $q$Privacy-conscious Reddit and RSS enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Following Hacker News without the firehose$q$, $q$Readers set score and keyword thresholds to receive only the most relevant Hacker News stories in their feed reader.$q$, $q$Developers and tech news readers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Self-hosted content aggregation for personal dashboards$q$, $q$Self-hosting enthusiasts combine Upvote RSS with tools like FreshRSS to build a personalized, ad-free content aggregation stack.$q$, $q$Homelab and self-hosting communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited feeds","Optional AI summaries with your own API key"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$overview$q$, $q$What Is Upvote RSS$q$, 2, ARRAY[$q$Upvote RSS is a self-hosted, open-source tool that converts the top-voted posts from Reddit, Hacker News, Lemmy, Mbin, PieFed, Lobsters, and GitHub into personalized RSS feeds. Instead of following a subreddit or forum directly and being overwhelmed by volume, users set score thresholds, keyword filters, and timeframes so only the most relevant posts appear in their feed reader.$q$, $q$Built by developer John Warne and distributed as open-source software on GitHub, the project is aimed at people who prefer a curated, low-noise reading experience inside an existing RSS reader rather than checking multiple social platforms directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Feeds can be tuned by score threshold, keyword inclusion or exclusion, time window, and target number of posts per day, giving fine control over feed volume and relevance. Upvote RSS embeds post media such as videos, image galleries, and thumbnails directly into the feed and uses parsers to extract clean article content from linked pages.$q$, $q$An optional AI summarization feature generates short article summaries using a configurable provider, including OpenAI, Anthropic, Google Gemini, Mistral, DeepSeek, Ollama, or any OpenAI-compatible endpoint, letting self-hosters choose a provider that fits their budget or privacy requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Upvote RSS is entirely free and open source; there is no paid tier, subscription, or hosted commercial version. Users run it themselves, typically via Docker or a PHP-capable web server, and only pay for their own hosting and, if they enable AI summaries, their own third-party AI API usage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d63cd81e-6805-4383-b257-12cd36fa4b4c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Feedback boards$q$, $q$Public or private boards where users submit, vote on, and comment on feature suggestions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Public roadmap$q$, $q$Shows planned, in-progress, and shipped items to keep customers informed and build trust.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Automated changelog$q$, $q$Notifies requesters automatically when the features they voted for ship.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$AI smart tags$q$, $q$Uses AI to automatically categorize and tag incoming feedback for easier triage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$AI duplicate merging$q$, $q$Detects and merges duplicate feedback items automatically to keep boards clean.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Custom branding and domains$q$, $q$White-label boards with custom domains and no Upvoty branding on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Integrations$q$, $q$Connects with Slack, Jira, Intercom, Zapier, and a REST API, plus MCP for AI assistants.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Multi-language support$q$, $q$Feedback boards can be localized into more than 20 languages for global audiences.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Affordable entry-level pricing compared to enterprise feedback tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$AI-assisted tagging and duplicate merging reduce manual triage work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Simple setup with public roadmap and changelog built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$14-day free trial with no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Wide language support for international products$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Lower tiers limit to a single project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Smaller ecosystem than larger competitors like Canny$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Public pricing page omits some enterprise-only detail, requiring a sales contact$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Small, bootstrapped team may mean slower feature velocity than VC-backed rivals$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$What does Upvoty do?$q$, $q$Upvoty is a feedback management platform where product teams collect user suggestions, let customers vote on them, and communicate progress through public roadmaps and changelogs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$How much does Upvoty cost?$q$, $q$Upvoty starts at $15/month for the Power plan, with Super at $25/month, Hyper at $49/month, and custom Enterprise pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Does Upvoty offer a free trial?$q$, $q$Yes, all plans include a 14-day free trial with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Who founded Upvoty?$q$, $q$Upvoty was founded in 2018 by Mike Strives and is based in Eindhoven, Netherlands.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Does Upvoty support single sign-on?$q$, $q$Yes, custom SSO is available starting on the Power plan, with SAML SSO included in Enterprise.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Can Upvoty detect duplicate feedback?$q$, $q$Yes, its AI-powered merge tool automatically detects and consolidates duplicate suggestions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$What integrations does Upvoty support?$q$, $q$Upvoty integrates with Slack, Jira, Intercom, Zapier, its own API, and offers an MCP integration for AI assistants.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Is Upvoty a good fit for enterprise companies?$q$, $q$Upvoty offers a custom Enterprise plan with SAML SSO, but it is primarily built and priced for startups and small-to-mid-sized product teams.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Prioritizing the product roadmap$q$, $q$Product managers use vote counts on the feedback board to decide which features to build next.$q$, $q$Product managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Closing the feedback loop with customers$q$, $q$Support and customer success teams notify users automatically via changelog when their requested features ship.$q$, $q$Customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Building a public-facing roadmap$q$, $q$Startups embed a branded, public roadmap on their website to build transparency and trust with early customers.$q$, $q$Startup founders and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Power$q$, $q$$15/month$q$, $q$monthly (10% discount annual)$q$, NULL, $q$["1 project","Unlimited boards","Unlimited tracked users","Public roadmap","Custom branding and domain","Custom SSO"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Super$q$, $q$$25/month$q$, $q$monthly (10% discount annual)$q$, NULL, $q$["Everything in Power","Changelog","All integrations","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Hyper$q$, $q$$49/month$q$, $q$monthly (10% discount annual)$q$, NULL, $q$["Everything in Super","Unlimited projects","Upvoty MCP","API and webhooks"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Unlimited everything","SAML SSO","Custom DPA","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$overview$q$, $q$What Is Upvoty$q$, 2, ARRAY[$q$Upvoty is a customer feedback and feature-voting platform that helps product teams collect ideas, let users vote on what matters most, and keep everyone informed through public roadmaps and changelogs. Founded in 2018 by Mike Strives as a bootstrapped, self-funded company in Eindhoven, Netherlands, it targets startups and small-to-mid-sized product teams looking for a lightweight alternative to enterprise feedback tools.$q$, $q$Customers embed a feedback board on their website or app, where users submit and upvote suggestions. Product teams triage that input, move items onto a public roadmap, and automatically notify requesters via changelog entries once a feature ships.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes public or private feedback boards with tagging, filtering, and moderation controls, a public roadmap view, and an automated changelog that notifies users when their requested features are released. AI-powered smart tags help categorize incoming feedback automatically, and an AI merge tool detects and consolidates duplicate suggestions to keep boards organized.$q$, $q$Upvoty also supports single sign-on, custom domains, white-label branding, more than 20 languages, and integrations with Slack, Jira, Intercom, Zapier, and its REST API, along with an MCP integration that lets AI assistants like ChatGPT and Claude query feedback data directly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b032034e-3c48-43b1-b97e-319af0c7611f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Upvoty offers four subscription tiers: Power at $15/month for a single project with unlimited boards and tracked users; Super at $25/month, its most popular plan, which adds changelogs, all integrations, and priority support; Hyper at $49/month, which unlocks unlimited projects, API and webhooks, and the Upvoty MCP integration; and a custom-priced Enterprise plan with unlimited everything, SAML SSO, and a dedicated success manager.$q$, $q$All plans include a 14-day free trial with no credit card required, and annual billing offers roughly a 10 percent discount versus paying monthly.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Combined image and file backups$q$, $q$Performs full disk image backups alongside continuous incremental file backups from the same system.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Continuous file monitoring$q$, $q$Watches folders for changes in real time to back up new or modified files quickly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Open-file backup$q$, $q$Backs up files that are actively in use, such as email archives, without interrupting the running system.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Web-based server interface$q$, $q$Configures backup jobs and monitors client status through a browser-based dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Deduplication$q$, $q$Stores identical files shared across multiple clients only once to reduce storage use.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Bare-metal recovery$q$, $q$Supports restoring a full system from a bootable USB or CD after a crash.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Remote and mobile client backup$q$, $q$Backs up devices over the internet, not just on the local network.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Cross-platform clients$q$, $q$Supports Windows, Linux, macOS, FreeBSD, and various NAS operating systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Completely free and open source with no per-device fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Combines image and file-level backup in one system$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Handles open files without interrupting active use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Deduplication reduces storage costs across many clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Supports remote/internet backups, not just LAN$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Interface is more utilitarian than modern commercial backup dashboards$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$No official vendor support contract; relies on community and forums$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Initial setup and tuning require some technical/sysadmin skill$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Smaller ecosystem of integrations compared to commercial backup suites$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Is UrBackup really free?$q$, $q$Yes, UrBackup is free, open-source software licensed under AGPLv3+, usable for both personal and commercial purposes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Who created UrBackup?$q$, $q$UrBackup was created by developer Martin Raiber, with the project active since around 2011.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Does UrBackup support bare-metal recovery?$q$, $q$Yes, you can restore a full system from a bootable USB or CD after hardware failure or a crash.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$What operating systems does UrBackup support?$q$, $q$It supports Windows, Linux, macOS, FreeBSD, and several NAS platforms for both server and client.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Can UrBackup back up files that are currently open?$q$, $q$Yes, it can back up open files such as active Outlook archives without interrupting the running application.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Does UrBackup deduplicate data?$q$, $q$Yes, identical files stored by multiple clients are only stored once on the server to save space.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Can UrBackup back up remote devices over the internet?$q$, $q$Yes, it supports backing up remote and mobile clients over the internet in addition to local network clients.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$How many UrBackup servers are in use?$q$, $q$The project reports more than 21,000 active server instances with auto-update enabled.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Small business network backup$q$, $q$IT administrators deploy a UrBackup server to protect all workstations and servers on a local network without per-device licensing costs.$q$, $q$Small business IT administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Home lab and self-hosted backup$q$, $q$Self-hosting enthusiasts run UrBackup to back up personal computers and NAS devices as part of a broader home lab setup.$q$, $q$Home lab and self-hosting hobbyists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Disaster recovery for critical systems$q$, $q$Organizations use UrBackup's image backups and bootable recovery media to restore crashed servers quickly after hardware failure.$q$, $q$Sysadmins and disaster recovery planners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full image and file backup","Unlimited clients","Deduplication","Bare-metal recovery"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$overview$q$, $q$What Is UrBackup$q$, 2, ARRAY[$q$UrBackup is a free, open-source backup system built around a client-server architecture, created by developer Martin Raiber with the project active since roughly 2011. It combines full image backups with continuous incremental file backups so that both bare-metal recovery and quick file-level restores are possible from the same system.$q$, $q$The software is distributed under the AGPLv3+ open-source license, so anyone can install, use, and modify it, including for commercial purposes, without paying license fees. It runs across Windows, Linux, macOS, FreeBSD, and several NAS platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$UrBackup clients continuously monitor watched folders for changes, allowing fast incremental backups without waiting for a scheduled full scan, and can back up files that are actively open, such as email archives. The server provides a web interface for configuring jobs and checking client status, plus deduplication that stores identical files across multiple clients only once.$q$, $q$Restores can be performed through the web interface, the client app, directly via Windows Explorer, or from a bootable USB or CD for full bare-metal system recovery. UrBackup also supports backing up remote and mobile clients over the internet, not just devices on a local network.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$UrBackup is entirely free and open source under the AGPLv3+ license, with no paid tiers or per-device licensing costs disclosed publicly. Users are responsible for their own server and client hardware, and community support is available through the project's forums and GitHub issue tracker.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b386442-acd6-4287-b601-254de09a7e9b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Job-change tracking$q$, $q$Alerts sales teams when past customers or champions move to a new company, a strong buying signal.$q$, 0);
