INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Gem-E AI scoring$q$, $q$A proprietary AI agent that analyzes hundreds of signals to build transparent, customizable lead scores.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$CRM and call data integration$q$, $q$Pulls in data from CRMs, call transcripts, and product usage to enrich scoring models.$q$, 3);
