INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Buying group targeting$q$, $q$Identifies and targets multiple stakeholders within a target account rather than a single contact.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$CRM and sales tool integrations$q$, $q$Connects with Salesforce, HubSpot, Marketo, Outreach, Salesloft, LinkedIn, Meta, and Google Ads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Custom research agent$q$, $q$An AI agent that can discover additional relevant signals beyond the built-in signal library.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Strong, well-known niche in job-change tracking for warm-lead reactivation$q$, 0);
