INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$No public pricing, requiring a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Likely priced for mid-market and enterprise budgets rather than small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Effectiveness depends heavily on the quality of connected CRM data$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Newer AI-agent outreach features are less established than the core job-change tracking product$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$What does UserGems do?$q$, $q$UserGems is a B2B sales intelligence platform that tracks buyer job changes and other intent signals, then uses AI to score and prioritize accounts for outbound sales and marketing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$When was UserGems founded?$q$, $q$UserGems was founded in 2019 by Christian Kletzl and is based in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$How much does UserGems cost?$q$, $q$UserGems does not publish pricing; you need to request a demo and receive a custom quote.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$What is Gem-E?$q$, $q$Gem-E is UserGems' proprietary AI agent that analyzes hundreds of signals to build transparent, customizable account and contact scoring models.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$What CRMs does UserGems integrate with?$q$, $q$UserGems integrates with Salesforce, HubSpot, Marketo, Outreach, and Salesloft, among other sales and marketing tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Does UserGems offer a guarantee?$q$, $q$Yes, UserGems offers a minimum 1x revenue ROI guarantee or a full refund.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$How much funding has UserGems raised?$q$, $q$UserGems has raised approximately $22.5 million from investors including Battery Ventures and Tiger Global Management.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Is UserGems only for job-change tracking?$q$, $q$No, while job-change tracking was its original focus, UserGems now aggregates 30-plus signals and offers AI-driven outreach orchestration across multiple channels.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Reactivating former customers$q$, $q$Sales teams get alerted when a past buyer or champion changes jobs, prompting timely outreach at the new company.$q$, $q$B2B account executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Account-based marketing prioritization$q$, $q$RevOps and marketing teams use aggregated intent signals to prioritize which target accounts to pursue first.$q$, $q$ABM and demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Coordinated buying-group outreach$q$, $q$Sales and marketing coordinate multi-channel messaging to several stakeholders within a single target account simultaneously.$q$, $q$Enterprise sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$Custom$q$, $q$Contact sales$q$, $q$custom$q$, NULL, $q$["Custom signal and integration package","Gem-E AI scoring","Multi-channel outreach orchestration","1x ROI guarantee"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$overview$q$, $q$What Is UserGems$q$, 2, ARRAY[$q$UserGems is a B2B sales intelligence platform, founded in 2019 by Christian Kletzl and based in San Francisco, that helps sales and marketing teams identify which buyers to target and when. It started with a focused idea: tracking job changes among a company's past customers and champions, since a former buyer moving to a new company is one of the strongest predictors of a new sale.$q$, $q$The platform has grown into a wider AI-driven command center for outbound and account-based marketing, combining more than 30 buying signals with an AI scoring and outreach engine to help revenue teams prioritize and reach the right accounts at the right time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$UserGems aggregates signals such as job changes, hiring activity, website visits, and M&amp;A events, and layers in data from a company's own CRM, call transcripts, and product usage. Its proprietary AI system, Gem-E, scores accounts and contacts using hundreds of signals and builds custom scoring models that learn from each customer's historical closed-won patterns.$q$, $q$On the activation side, UserGems can orchestrate outreach across ads, email sequences, and CRM record updates, coordinating messaging to multiple stakeholders within a target buying group simultaneously, and syncs with tools like Salesforce, HubSpot, Outreach, and Salesloft.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e257953a-6b46-421c-9a74-ccd15dc7c9a2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$UserGems does not publish pricing on its website; prospective customers must request a demo and receive a custom quote based on team size and desired signals/features. The company backs its platform with a guarantee of at least 1x revenue ROI or a full refund, and it markets outcomes such as a median 47x pipeline ROI from customer case studies.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$No-code product tours$q$, $q$Build interactive onboarding tours and walkthroughs using a Chrome extension without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$In-app engagement elements$q$, $q$Includes tooltips, hotspots, banners, modals, and checklists to guide and engage users.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$In-app knowledge base$q$, $q$Provides a searchable self-service knowledge base embedded directly inside the product.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$AI Assistant with MCP$q$, $q$An AI-powered support assistant that can connect to external AI tools via MCP Server integration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$In-app surveys and NPS$q$, $q$Collects user feedback and Net Promoter Score data directly within the product.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Session replay$q$, $q$Records user sessions to help teams understand behavior and identify friction points.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Segmentation and personalization$q$, $q$Targets different onboarding experiences to specific user segments based on behavior or attributes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$A/B testing and goal tracking$q$, $q$Tests different onboarding flows against each other and tracks conversion goals (Growth plan and above).$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Fast, no-code setup that doesn't require developer involvement$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Broad feature set spanning onboarding, support, and analytics in one tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Strong compliance certifications (SOC 2, GDPR, HIPAA, ISO 27001)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Competitive pricing relative to enterprise onboarding platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$30-day money-back guarantee on paid plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Session recording and guide limits on lower tiers may be restrictive for larger products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Advanced features like A/B testing require the higher Growth tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Smaller funding and team size than larger competitors like WalkMe$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Chrome extension-based editor may feel less flexible than fully code-based customization$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$What is UserGuiding used for?$q$, $q$UserGuiding is used to build no-code in-app onboarding experiences, product tours, and self-service support content to improve user adoption.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Does UserGuiding have a free plan?$q$, $q$Yes, its Support Essentials plan is free forever and includes the knowledge base and resource center features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$How much does UserGuiding cost?$q$, $q$Paid plans start at $174/month for Starter billed annually, with Growth at $349/month annually and custom Enterprise pricing above that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$When was UserGuiding founded?$q$, $q$UserGuiding was founded in 2017 and is headquartered in Istanbul, Turkey.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Does UserGuiding require coding skills?$q$, $q$No, product tours and other in-app content are built using a no-code Chrome extension.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Is UserGuiding SOC 2 compliant?$q$, $q$Yes, UserGuiding holds SOC 2 Type 2, GDPR, HIPAA, ISO 27001, and LGPD certifications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Can UserGuiding record user sessions?$q$, $q$Yes, session replay is included starting on the Starter plan, with a set number of recordings per month.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$What companies use UserGuiding?$q$, $q$UserGuiding says it is used by more than 1,000 teams, including reported customers like Uber, Elastic, Renault, and Digital Ocean.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$New user onboarding$q$, $q$SaaS product teams build guided tours and checklists to help new users reach their first value moment faster.$q$, $q$Product and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Self-service customer support$q$, $q$Support teams deploy an in-app knowledge base and AI Assistant to reduce ticket volume for common questions.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Feature adoption campaigns$q$, $q$Teams use banners, tooltips, and segmentation to drive adoption of new or underused features among existing users.$q$, $q$Product marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Support Essentials$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Knowledge base and product updates","Resource center and AI Assistant","Unlimited domains"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Starter$q$, $q$$174/month$q$, $q$annual$q$, NULL, $q$["Up to 100 active guides","Unlimited hotspots and checklists","5,000 session recordings","5 team seats","10 active surveys"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Growth$q$, $q$$349/month$q$, $q$annual$q$, NULL, $q$["A/B testing and goal tracking","Custom CSS and localization","Premium integrations","15 team seats","5 customizable themes"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["SOC2, GDPR, HIPAA compliance","SAML SSO and activity logs","Dedicated customer success manager","Unlimited everything"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$overview$q$, $q$What Is UserGuiding$q$, 2, ARRAY[$q$UserGuiding is a no-code product adoption platform, founded in 2017 and based in Istanbul, Turkey, that lets product and customer success teams build in-app onboarding experiences without writing code. Using a Chrome extension, teams can create guided tours, tooltips, and checklists and publish them in minutes rather than waiting on engineering resources.$q$, $q$Beyond onboarding, UserGuiding also offers self-service support tools, including an in-app knowledge base and AI Assistant, as well as feedback and analytics features like NPS surveys and session replay, positioning it as an all-in-one product adoption suite rather than a single-purpose tour builder.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core building blocks include product tours, tooltips, hotspots, banners, modals, and checklists, all created through a no-code Chrome extension with instant preview and publishing. In-app support tools include a searchable knowledge base, an AI Assistant with MCP Server integration, and Resource Centers for self-service help.$q$, $q$The platform also supports in-app surveys and NPS tracking, session replay, and behavioral segmentation for personalizing which experiences different user groups see, plus more than 15 total tools across onboarding, engagement, and analytics categories.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$UserGuiding offers a free Support Essentials plan covering the knowledge base, resource center, and AI Assistant with unlimited domains. The paid Starter plan costs $174/month billed annually and includes up to 100 active guides, unlimited hotspots and checklists, 10 active surveys, 5,000 session recordings, and 5 team seats.$q$, $q$The Growth plan is $349/month billed annually and adds A/B testing, goal tracking, custom CSS, localization, premium integrations, and 15 team seats. An Enterprise plan offers custom pricing with SOC 2, GDPR, and HIPAA compliance, SAML SSO, and a dedicated customer success manager; all paid plans include a 30-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9b0d980b-c01e-40ef-a82b-19f1c57289fc', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Visual workflow builder$q$, $q$Automates multi-step customer lifecycle campaigns through a drag-and-drop visual editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Account-level automation$q$, $q$Natively models many-to-many relationships between users and companies for B2B-style targeting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Transactional email$q$, $q$Sends receipts, password resets, and other transactional notifications alongside marketing email.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$In-app messaging$q$, $q$Delivers in-app messages and broadcasts in addition to email-based communication.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Dynamic segmentation$q$, $q$Segments users and companies dynamically based on behavior, properties, and events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$A/B/C testing$q$, $q$Tests multiple message variants against each other with conversion goal tracking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Custom properties and events$q$, $q$Tracks custom user and company attributes and events to power precise targeting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Webhooks and API$q$, $q$Connects Userlist to other tools and custom workflows via webhooks and a developer API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Purpose-built for SaaS account structures, unlike generic email tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Combines lifecycle email, transactional email, and in-app messaging in one product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Small, hands-on support team of engineers rather than a large call center$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Handles complex many-to-many user-to-company relationships natively$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$20 percent discount for annual billing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Pricing scales with monthly active users, which can get costly at high volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Smaller integration marketplace than larger platforms like Intercom$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$No published pricing for Professional or Enterprise tiers without contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Small team size may mean slower feature rollout compared to larger competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$What is Userlist used for?$q$, $q$Userlist is used by SaaS companies to automate lifecycle email, transactional email, and in-app messaging based on user and account behavior.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$How much does Userlist cost?$q$, $q$The Basic plan starts around $119-149/month for up to 10,000 monthly active users, with the Professional plan priced higher per MAU and Enterprise custom-priced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Who founded Userlist?$q$, $q$Userlist was founded in 2017 by Jane Portman, Benedikt Deicke, and Claire Suellentrop and is based in Atlanta, Georgia.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$How is Userlist different from Intercom or Customer.io?$q$, $q$Userlist natively supports account-level, many-to-many user-to-company data structures common in B2B SaaS, which generic tools like Intercom or Customer.io typically require workarounds to handle.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Does Userlist support transactional email?$q$, $q$Yes, it can send transactional emails like receipts and password resets alongside marketing and lifecycle campaigns.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Does Userlist offer a free trial?$q$, $q$Yes, Userlist offers a 14-day free trial before requiring a paid subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Is Userlist part of an accelerator program?$q$, $q$Yes, Userlist joined the 2020 batch of TinySeed, a SaaS-focused startup accelerator.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Can Userlist run A/B tests?$q$, $q$Yes, A/B/C testing with conversion goal tracking is available starting on the Professional plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$SaaS trial-to-paid onboarding$q$, $q$Product teams build automated email and in-app sequences to guide free trial users toward converting to paid plans.$q$, $q$SaaS product marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Account-based lifecycle messaging$q$, $q$B2B SaaS companies target messaging based on company-level behavior across multiple users within an account.$q$, $q$B2B SaaS growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Transactional and lifecycle email consolidation$q$, $q$Teams replace separate transactional and marketing email tools with a single platform covering both.$q$, $q$Founders and small marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Basic$q$, $q$From about $119/month (10,000 MAU, annual)$q$, $q$monthly or annual$q$, NULL, $q$["Lifecycle and transactional email","In-app messages and notifications","Visual workflow builder","5 team seats","20 custom properties, 20 custom events"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Professional$q$, $q$Higher per-MAU rate than Basic$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Basic","A/B/C testing and conversion goals","Advanced integrations","10 team seats","Unlimited custom events"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Custom message limits","Dedicated account manager","Done-for-you data planning","Monthly review calls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$overview$q$, $q$What Is Userlist$q$, 2, ARRAY[$q$Userlist is a customer messaging and lifecycle email automation platform built specifically for SaaS companies, founded in 2017 by Jane Portman, Benedikt Deicke, and Claire Suellentrop and based in Atlanta, Georgia. The company joined the TinySeed SaaS accelerator's 2020 batch and has grown as a small, focused team rather than pursuing large-scale venture funding.$q$, $q$Unlike general-purpose email marketing tools, Userlist is designed around how SaaS products actually work: users often belong to companies, hold different roles, and their behavior needs to be tracked and automated at both the individual and account level.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Userlist's visual workflow builder automates customer journeys such as onboarding sequences, trial-conversion nudges, and re-engagement campaigns, combining marketing email, transactional email, and in-app messages in a single tool. It supports dynamic segmentation of both individual users and companies, letting teams target messages based on account-level behavior, not just individual actions.$q$, $q$Additional capabilities include A/B/C testing with conversion goal tracking, custom properties and events for detailed targeting, broadcast messaging, webhook integration, and an API for custom workflows, along with subscription preference management to keep unsubscribe handling compliant.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Userlist's Basic plan starts at roughly $119-149/month for up to 10,000 monthly active users, with additional users billed at about $10 per extra 1,000, and includes lifecycle and transactional email, in-app messaging, segmentation, and the visual workflow builder with 5 team seats. The Professional plan raises the per-MAU rate slightly (around $12 per 1,000 additional users) and adds A/B/C testing, advanced workflow features, more integrations, and unlimited custom events with 10 team seats.$q$, $q$A custom-priced Enterprise plan adds dedicated account management, done-for-you data migration and planning, and monthly review calls. Annual billing saves roughly 20 percent compared to paying monthly.$q$]::text[], 2);
