-- ── Uptrace ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Uptrace is an open-source, OpenTelemetry-native observability platform built on ClickHouse that unifies distributed traces, metrics, and logs in a single dashboard for application performance monitoring.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted or 50GB/month free on Cloud, then from $0.075/GB)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Chisinau, Moldova$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Uptrace Review: OpenTelemetry APM Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Uptrace unifies traces, metrics, and logs on OpenTelemetry and ClickHouse. See its pricing, features, and how it compares to Datadog and Grafana.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Uptrace is an open-source application performance monitoring and observability platform founded in 2021 by Vladimir Mihailenco, based in Chisinau, Moldova. It is built entirely on open standards: OpenTelemetry for instrumentation and data collection, and ClickHouse as the underlying columnar database, which lets it handle high-cardinality trace, metric, and log data efficiently. Uptrace unifies distributed tracing, metrics, and logs in one interface, with a service graph that shows dependencies and RED metrics (rate, errors, duration) to help teams spot bottlenecks. It also ingests data from Prometheus, Vector, FluentBit, and CloudWatch, and offers an MCP-compatible interface so AI assistants like Claude can query telemetry data in plain language. The Community Edition is fully open source under AGPL-3.0 and free to self-host with no feature limits via Docker, Kubernetes, or Ansible. Uptrace Cloud uses usage-based pricing: the first 50GB of traces/logs and 5,000 metric timeseries per month are free, after which data is billed per gigabyte (starting around $0.075-$0.10/GB with volume discounts) and metrics per million datapoints, with unlimited users, services, and hosts at every tier -- no per-seat charges. Uptrace positions itself as a lower-cost, vendor-neutral alternative to Datadog, New Relic, and Splunk, citing cost comparisons where a large engineering team's monthly bill can run roughly 90 percent cheaper than equivalent Datadog or New Relic usage. It competes most directly with other OpenTelemetry-native, ClickHouse-backed tools such as SigNoz and with self-hosted stacks combining Grafana, Tempo, and Loki.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e7a0b53e-f0d9-4f9d-ac95-70d431887088';

