-- ── Upvote RSS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Upvote RSS is a free, self-hosted, open-source tool that turns top posts from Reddit, Hacker News, Lemmy, Mbin, and GitHub into filtered, enriched RSS feeds for any feed reader.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Upvote RSS: Self-Hosted RSS Feeds From Reddit and Hacker News$q$, seo_title),
  seo_meta_description = COALESCE($q$Upvote RSS turns Reddit, Hacker News, and Lemmy top posts into filtered, self-hosted RSS feeds with AI summaries. See how it works and how to set it up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Upvote RSS is a free, open-source, self-hosted PHP tool created by developer John Warne that generates curated RSS feeds from social aggregation sites including Reddit, Hacker News, Lemmy, Lobsters, PieFed, Mbin, and GitHub. Rather than subscribing to a raw, high-volume subreddit or Hacker News firehose, users configure a feed by picking a source community or platform and setting filters such as minimum score thresholds, keyword filters, timeframes, and desired posts-per-day, so the resulting feed only contains the most relevant, highly-upvoted content. The tool goes beyond simple feed generation by embedding post media (videos, image galleries, thumbnails), extracting and cleaning article content with built-in parsers, and optionally generating AI-written summaries of linked articles using a choice of providers including OpenAI, Anthropic, Google Gemini, Mistral, DeepSeek, Ollama, or any OpenAI-compatible API. The project is hosted on GitHub, distributed as open-source software, and is commonly deployed via Docker or a standard PHP web server, making it a favorite among the self-hosting and privacy-conscious RSS reader community documented on sites like selfh.st and r/selfhosted. There is no commercial pricing: the entire tool is free to download, run, and modify, with users supplying their own hosting and, optionally, their own AI provider API keys for the summarization feature. It fills a niche distinct from mainstream feed readers or dedicated commercial monitoring tools by focusing narrowly on converting noisy social-aggregation upvote streams into a low-volume, high-signal RSS feed a person can comfortably read in their existing feed reader.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd63cd81e-6805-4383-b257-12cd36fa4b4c';

