-- ── Upvoty ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Upvoty is an all-in-one customer feedback platform where product teams collect feature requests, let users vote on ideas, and communicate progress through public roadmaps and changelogs.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$15/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Eindhoven, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Upvoty Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Upvoty lets teams collect feedback, run public roadmaps, and ship changelogs. Compare its pricing plans and features before you sign up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Upvoty is a bootstrapped customer feedback management SaaS founded in 2018 by Mike Strives and based in Eindhoven, Netherlands. It gives product and support teams a public or private feedback board where customers submit ideas, vote and comment on existing suggestions, and follow along as items move through a public roadmap from planned to in-progress to shipped. When a feature launches, Upvoty can automatically notify the users who requested it via an integrated changelog. Additional features include AI-assisted smart tagging to categorize incoming feedback, an AI-powered merge tool that detects and consolidates duplicate suggestions, single sign-on, custom domains and branding, multi-language support across 20-plus languages, and integrations with Slack, Jira, Intercom, Zapier, and a REST API, plus an MCP integration for querying feedback data from AI assistants like ChatGPT and Claude. As of a 2023 revenue disclosure, Upvoty reported around $480K in annual recurring revenue as a small, self-funded, bootstrapped team, and it says it is trusted by more than 2,000 product teams including companies like Veed. Pricing is subscription-based across four tiers, Power at $15/month, Super at $25/month (its most popular plan, adding changelogs and all integrations), Hyper at $49/month (unlimited projects and API/webhooks), and a custom-priced Enterprise tier with SAML SSO and a dedicated success manager, all backed by a 14-day free trial requiring no credit card. Upvoty competes with feedback and roadmap tools such as Canny, Featurebase, UserVoice, and Frill, generally positioning itself as a simpler, more affordable option for small and mid-sized product teams rather than large enterprises.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b032034e-3c48-43b1-b97e-319af0c7611f';

