-- ── UrBackup ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$UrBackup is a free, open-source client-server backup system that combines fast incremental file backups with full image backups for Windows, Linux, and macOS.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$UrBackup: Free Open-Source Client-Server Backup Software$q$, seo_title),
  seo_meta_description = COALESCE($q$UrBackup is a free, open-source backup system combining image and file backups with fast restore. See its features, licensing, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$UrBackup is a free, open-source client-server backup solution created by developer Martin Raiber, with the project dating back to around 2011. It is licensed under the OSI-certified AGPLv3+, meaning it can be used, modified, and redistributed for free in both personal and commercial settings under open-source license terms. UrBackup combines full disk/image backups with continuous, incremental file backups: a lightweight client monitors folders for changes in real time so that new or modified files are backed up quickly without waiting for a scheduled full run, and backups can proceed even while files are open, such as active Outlook archives. The server exposes a web interface for configuring backup jobs, managing clients, and monitoring backup status, and offers multiple restore paths, restoring from the web UI, from the client application, directly through Windows Explorer, or via a bootable USB/CD for full bare-metal recovery of a crashed system. UrBackup also deduplicates files across clients so identical files stored by multiple machines are only kept once on the server, saving disk space, and it supports backing up remote or mobile clients over the internet, not just local networks. It runs on Windows, Linux, macOS, FreeBSD, and various NAS platforms, making it popular with home labs, small businesses, and IT administrators who want self-hosted backup infrastructure without per-device licensing fees. The project reports more than 21,000 active server instances with auto-update enabled. UrBackup is maintained by its original author alongside a company, Infscape UG, and continues active development on GitHub, with the free open-source edition as its only distribution model -- there is no separate paid commercial tier disclosed publicly.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b386442-acd6-4287-b601-254de09a7e9b';

