-- ── UserGems ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$UserGems is an AI-powered sales intelligence platform that tracks buyer job changes and 30-plus other intent signals to help B2B sales and marketing teams find and reach the right prospects.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$UserGems Review: Sales Intelligence and Job-Change Tracking$q$, seo_title),
  seo_meta_description = COALESCE($q$UserGems tracks buyer job changes and intent signals for B2B sales teams. See how it works, its AI scoring, and what it costs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$UserGems is a B2B sales intelligence and account-based marketing platform founded in 2019 by Christian Kletzl, headquartered in San Francisco, California. The company has raised roughly $22.5 million from investors including Battery Ventures, Tiger Global Management, and Kearny Jackson. UserGems was originally best known for tracking job changes among past customers and champions, alerting sales reps when a former buyer moves to a new company, since that buyer is statistically more likely to purchase again. The platform has since expanded into a broader AI-driven outbound and ABM command center: it aggregates more than 30 native intent signals, including job changes, website visits, hiring activity, and M&amp;A events, and combines them with data pulled from CRMs, call transcripts, and product usage. A proprietary AI system called Gem-E analyzes hundreds of signals to build transparent, customizable lead-scoring models that learn from each customer's own closed-won deal patterns, and the platform can deploy AI agents to orchestrate personalized, multi-channel outreach across ads, email, and CRM updates, targeting entire buying groups rather than single contacts. UserGems integrates with Salesforce, HubSpot, Marketo, Outreach, Salesloft, LinkedIn, Meta, and Google Ads, and is SOC 2 certified with GDPR and CCPA compliance. Pricing is not published; prospective customers must request a demo, and the company offers a guarantee of at least 1x revenue ROI or a full refund, citing customer results such as a median 47x pipeline return. UserGems competes with sales intelligence and intent-data platforms like ZoomInfo, 6sense, Clearbit (now part of HubSpot), and Apollo.io, and is generally positioned toward mid-market and enterprise B2B sales teams running outbound and ABM programs rather than small businesses.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e257953a-6b46-421c-9a74-ccd15dc7c9a2';

