-- ── Userlist ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Userlist is a customer messaging and lifecycle email automation platform built specifically for SaaS companies, combining visual workflows, in-app messages, and account-level segmentation.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$119/month (10,000 MAU, billed annually)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Atlanta, Georgia, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Userlist Review: SaaS Email Automation Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Userlist is a lifecycle email and in-app messaging tool built for SaaS. See its pricing, key features, and how it compares to Customer.io and Intercom.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Userlist is a customer messaging and lifecycle email automation platform purpose-built for SaaS companies, founded in 2017 by Jane Portman, Benedikt Deicke, and Claire Suellentrop and based in Atlanta, Georgia. The founders signed an informal collaboration agreement in October 2017 and the company later joined the 2020 batch of TinySeed, the SaaS-focused accelerator run by Rob Walling and Einar Vollset, remaining a small, bootstrapped-style team of around five people as of recent public revenue data showing about $1 million in annual revenue. Userlist lets product marketers and founders build customer lifecycle campaigns through a visual workflow builder, combining marketing email, transactional email (receipts, password resets, notifications), and in-app messages and broadcasts in one tool. Its key differentiator is native support for account-level, B2B-style data structures: unlike many email tools built for one-to-one consumer relationships, Userlist models many-to-many relationships between users and companies with different roles, letting teams automate messaging based on account-level behavior rather than only individual user actions. Other features include dynamic segmentation, A/B/C testing with conversion goal tracking, custom properties and events, webhook and API access, and subscription preference management. Userlist positions itself directly against Intercom, Drip, and Customer.io, arguing that generic tools require workarounds for SaaS-specific account structures that Userlist handles natively, and it emphasizes direct support from its own engineers rather than a large support organization. Pricing is usage-based on monthly active users: the Basic plan starts around $119-149/month for up to 10,000 MAU with additional users billed per 1,000, and includes lifecycle email, in-app messaging, and the workflow builder; the Professional plan costs more per MAU but adds A/B/C testing, advanced integrations, and unlimited custom events; and a custom Enterprise plan adds dedicated account management and done-for-you data planning. Annual billing offers roughly a 20 percent discount versus monthly.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '95a1cd47-8a75-47d2-b10b-b9d86a58c71c';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '95a1cd47-8a75-47d2-b10b-b9d86a58c71c' AND logo IS NULL AND website IS NOT NULL;

